import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { DataEntry } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async queryKnowledgeBase(query: string, contextData: DataEntry[]): Promise<{ text: string; relevantIds: string[] }> {
    const dataContextStr = contextData.map(d => 
      `[Topic: ${d.topic}, Value: ${d.value} ${d.unit}, Country: ${d.country}, Year: ${d.year}, Source: ${d.source}, ReportID: ${d.reportId || 'N/A'}, ID: ${d.id}]`
    ).join('\n');

    const systemInstruction = `
      You are a specialized Data Privacy Scientist Assistant. Your goal is to help users retrieve and interpret historical risk assessment data.

      Historical Context Data provided:
      ${dataContextStr}

      Instructions:
      1. Always prioritize answering using the historical data provided above if it is relevant.
      2. If you use a piece of data, mention the source, year, and its Report ID if available.
      3. If the data isn't in the provided context, state that clearly but try to provide general scientific knowledge as a backup.
      4. Format your response in clean Markdown.
      5. At the end of your response, strictly output a JSON array of the "ID"s of the data points you referenced in your answer, like this: DATA_REFS: ["id1", "id2"].
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: MODEL_NAME,
        contents: query,
        config: {
          systemInstruction,
          temperature: 0.2,
        }
      });

      const text = response.text || "I'm sorry, I couldn't process that request.";
      const refMatch = text.match(/DATA_REFS: \[(.*?)\]/);
      const relevantIds = refMatch 
        ? refMatch[1].split(',').map(s => s.trim().replace(/"/g, '')) 
        : [];
      const cleanedText = text.replace(/DATA_REFS: \[.*?\]/, '').trim();

      return { text: cleanedText, relevantIds };
    } catch (error) {
      console.error("Gemini Query Error:", error);
      return { text: "Error connecting to AI.", relevantIds: [] };
    }
  }

  async extractDataEntries(text: string): Promise<Partial<DataEntry>[]> {
    const systemInstruction = `
      Extract specific data points (statistics, prevalence rates, etc.) from the provided text or links.
      For each data point found, create a structured object with:
      - topic: What the data is about
      - value: The numerical value
      - unit: The unit
      - country: The specific country or region
      - year: The year the data refers to
      - source: The source or link
      - category: One of ['Epidemiology', 'Privacy Metrics', 'Demographics', 'Other']
      - reportId: If a report ID like "DXX-XXX" (e.g., D25-348) is mentioned in context, extract it. Otherwise leave empty string.

      Return a JSON array of these objects.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: MODEL_NAME,
        contents: text,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                topic: { type: Type.STRING },
                value: { type: Type.STRING },
                unit: { type: Type.STRING },
                country: { type: Type.STRING },
                year: { type: Type.STRING },
                source: { type: Type.STRING },
                category: { type: Type.STRING },
                reportId: { type: Type.STRING, description: "Extract report ID like D25-348 if present" },
              },
              required: ["topic", "value", "unit", "country", "year", "source", "category", "reportId"]
            }
          }
        }
      });

      return JSON.parse(response.text || "[]");
    } catch (error) {
      console.error("Extraction Error:", error);
      return [];
    }
  }
}

export const gemini = new GeminiService();

import React, { useState } from 'react';
import { DataEntry } from '../types';

interface KnowledgeBaseProps {
  entries: DataEntry[];
  onAddEntry: (entry: Omit<DataEntry, 'id' | 'dateAdded'>) => void;
  onUpdateEntry: (entry: DataEntry) => void;
  onRemoveEntry: (id: string) => void;
  onImport: (data: DataEntry[]) => void;
}

const KnowledgeBase: React.FC<KnowledgeBaseProps> = ({ entries, onAddEntry, onUpdateEntry, onRemoveEntry, onImport }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [entryToDelete, setEntryToDelete] = useState<DataEntry | null>(null);
  const [editingEntry, setEditingEntry] = useState<DataEntry | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [formData, setFormData] = useState({
    topic: '', value: '', unit: '', country: '', year: '', source: '', category: 'Epidemiology' as any, reportId: '', notes: ''
  });

  const filteredEntries = entries.filter(e => 
    e.topic.toLowerCase().includes(searchTerm.toLowerCase()) || 
    e.country.toLowerCase().includes(searchTerm.toLowerCase()) ||
    e.source.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (e.reportId && e.reportId.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const openAddModal = () => {
    setEditingEntry(null);
    setFormData({ topic: '', value: '', unit: '', country: '', year: '', source: '', category: 'Epidemiology', reportId: '', notes: '' });
    setIsModalOpen(true);
  };

  const openEditModal = (entry: DataEntry) => {
    setEditingEntry(entry);
    setFormData({
      topic: entry.topic,
      value: entry.value,
      unit: entry.unit,
      country: entry.country,
      year: entry.year,
      source: entry.source,
      category: entry.category,
      reportId: entry.reportId || '',
      notes: entry.notes || ''
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingEntry) {
      onUpdateEntry({ ...editingEntry, ...formData });
    } else {
      onAddEntry(formData);
    }
    setIsModalOpen(false);
  };

  const confirmDelete = () => {
    if (entryToDelete) {
      onRemoveEntry(entryToDelete.id);
      setEntryToDelete(null);
    }
  };

  const handleExport = () => {
    const dataStr = JSON.stringify(entries, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `privacy-vault-export-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
          onImport(json);
        } else {
          alert("Invalid format: expected a JSON array of entries.");
        }
      } catch (err) {
        alert("Error parsing JSON file.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Knowledge Matching Lab</h2>
          <p className="text-slate-500">Manage your historical citations and research data points.</p>
        </div>
        <div className="flex gap-3">
          <label className="bg-slate-100 hover:bg-slate-200 text-slate-700 px-4 py-2 rounded-lg cursor-pointer transition flex items-center gap-2">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
            </svg>
            Import JSON
            <input type="file" className="hidden" accept=".json" onChange={handleFileUpload} />
          </label>
          <button 
            onClick={handleExport}
            className="bg-slate-100 hover:bg-slate-200 text-slate-700 px-4 py-2 rounded-lg transition flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
            Export
          </button>
          <button 
            onClick={openAddModal}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg shadow-md transition flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            New Entry
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50/50">
          <div className="relative">
            <span className="absolute inset-y-0 left-0 flex items-center pl-3">
              <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </span>
            <input
              type="text"
              placeholder="Search keyword, country, source, or Report ID..."
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none transition"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="text-xs text-slate-500 uppercase bg-slate-50 font-semibold">
