                </tr>
              )) : (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-400">
                    No data entries found. Start by adding one or importing a file.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Entry Modal (Add/Edit) */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-lg ${editingEntry ? 'bg-indigo-50 text-indigo-600' : 'bg-blue-50 text-blue-600'}`}>
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={editingEntry ? "M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5" : "M12 4v16m8-8H4"} />
                  </svg>
                </div>
                <h3 className="text-xl font-bold text-slate-800">
                  {editingEntry ? 'Edit Citation Entry' : 'New Citation Entry'}
                </h3>
              </div>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Topic / Disease / Metric</label>
                  <input required type="text" className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition" value={formData.topic} onChange={e => setFormData({...formData, topic: e.target.value})} placeholder="e.g., Type 2 Diabetes Prevalence" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Report ID</label>
                  <input type="text" className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition font-mono text-sm uppercase" value={formData.reportId} onChange={e => setFormData({...formData, reportId: e.target.value})} placeholder="e.g., D25-348" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Category</label>
                  <select 
                    className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition" 
                    value={formData.category} 
                    onChange={e => setFormData({...formData, category: e.target.value as any})}
                  >
                    <option value="Epidemiology">Epidemiology</option>
                    <option value="Privacy Metrics">Privacy Metrics</option>
                    <option value="Demographics">Demographics</option>
                    <option value="Other">Other</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Value</label>
                  <input required type="text" className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition" value={formData.value} onChange={e => setFormData({...formData, value: e.target.value})} placeholder="e.g., 8.5" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Unit</label>
                  <input required type="text" className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition" value={formData.unit} onChange={e => setFormData({...formData, unit: e.target.value})} placeholder="e.g., %" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Country</label>
                  <input required type="text" className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition" value={formData.country} onChange={e => setFormData({...formData, country: e.target.value})} placeholder="e.g., China" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Year</label>
                  <input required type="text" className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition" value={formData.year} onChange={e => setFormData({...formData, year: e.target.value})} placeholder="e.g., 2023" />
                </div>
                <div className="col-span-2">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Source (Citation)</label>
                  <input required type="text" className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition" value={formData.source} onChange={e => setFormData({...formData, source: e.target.value})} placeholder="URL or Document title" />
                </div>
              </div>
              <div className="pt-6 flex gap-3">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-3 rounded-xl transition"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className={`flex-[2] ${editingEntry ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-blue-600 hover:bg-blue-700'} text-white font-bold py-3 rounded-xl transition shadow-lg`}
                >
                  {editingEntry ? 'Save Changes' : 'Add to Vault'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {entryToDelete && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 text-center">
              <div className="w-16 h-16 bg-red-50 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </div>
              <h3 className="text-xl font-bold text-slate-800 mb-2">Delete Citation?</h3>
              <p className="text-slate-500 text-sm mb-6">
                Are you sure you want to remove <span className="font-bold text-slate-700">{entryToDelete.topic}</span>? This action cannot be undone.
              </p>
              <div className="flex gap-3">
                <button 
                  onClick={() => setEntryToDelete(null)}
                  className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-3 rounded-xl transition"
                >
                  Cancel
                </button>
                <button 
                  onClick={confirmDelete}
                  className="flex-1 bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded-xl transition shadow-lg"
                >
                  Delete
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default KnowledgeBase;

import React, { useState } from 'react';
import { DataEntry } from '../types';
import { gemini } from '../services/geminiService';

interface SmartExtractionProps {
  onAddEntries: (entries: Omit<DataEntry, 'id' | 'dateAdded'>[]) => void;
}

const SmartExtraction: React.FC<SmartExtractionProps> = ({ onAddEntries }) => {
  const [inputText, setInputText] = useState('');
  const [extractedData, setExtractedData] = useState<Partial<DataEntry>[]>([]);
  const [isExtracting, setIsExtracting] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [batchReportId, setBatchReportId] = useState('');

  const handleExtract = async () => {
    if (!inputText.trim()) return;
    setIsExtracting(true);
    setIsSaved(false);
    try {
      const data = await gemini.extractDataEntries(inputText);
      // If AI didn't find a report ID but user has a batch ID, apply it
      const processedData = data.map(item => ({
        ...item,
        reportId: item.reportId || batchReportId || ''
      }));
      setExtractedData(processedData);
    } catch (error) {
      console.error(error);
      alert("Failed to extract data. Please try again.");
    } finally {
      setIsExtracting(false);
    }
  };

  const handleSaveAll = () => {
    const validEntries = extractedData.filter(d => d.topic && d.value).map(d => ({
      ...d,
      reportId: d.reportId || batchReportId || ''
    })) as Omit<DataEntry, 'id' | 'dateAdded'>[];

    onAddEntries(validEntries);
    setExtractedData([]);
    setInputText('');
    setBatchReportId('');
    setIsSaved(true);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in duration-500">
      <div className="space-y-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">AI Data Extractor</h2>
          <p className="text-slate-500">Paste report snippets or links to automatically identify metrics.</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase mb-1 tracking-wider">Default Report ID (Optional)</label>
            <input 
              type="text" 
              className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none transition font-mono uppercase text-sm"
              placeholder="e.g. D25-348"
              value={batchReportId}
              onChange={(e) => setBatchReportId(e.target.value)}
            />
            <p className="text-[10px] text-slate-400 mt-1">If set, this ID will be applied to all extracted items unless the AI finds a specific one.</p>
          </div>

          <textarea
            className="w-full h-56 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none resize-none transition"
            placeholder="Paste text here... (e.g. 'Report D25-348 notes that 12% of people...')"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
          ></textarea>

          <button
            onClick={handleExtract}
            disabled={isExtracting || !inputText.trim()}
            className="w-full bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-bold py-3 rounded-xl shadow-lg transition flex items-center justify-center gap-2"
          >
            {isExtracting ? (
              <>
                <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Extracting Insights...
              </>
            ) : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.691.34a6 6 0 01-3.86.517l-2.388-.477a2 2 0 00-1.022.547l-1.16 1.16a2 2 0 002.828 2.828l1.16-1.16z" />
                </svg>
                Run AI Extraction
              </>
            )}
          </button>
        </div>

        {isSaved && (
          <div className="p-4 bg-green-50 border border-green-200 rounded-xl text-green-700 flex items-center gap-3 animate-in fade-in duration-300">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
            Data successfully added to your Matching Lab!
          </div>
        )}
      </div>

      <div className="space-y-6">
        <div className="flex justify-between items-center">
          <h3 className="text-xl font-bold text-slate-800">Preview & Confirm</h3>
          {extractedData.length > 0 && (
            <button 
              onClick={handleSaveAll}
              className="text-blue-600 hover:text-blue-700 font-bold text-sm underline px-2 py-1 hover:bg-blue-50 rounded transition"
            >
              Add all to Vault
            </button>
          )}
        </div>

        <div className="space-y-4 max-h-[calc(100vh-250px)] overflow-y-auto pr-2 custom-scrollbar">
          {extractedData.length === 0 ? (
            <div className="bg-slate-50 border border-dashed border-slate-300 rounded-2xl p-12 text-center text-slate-400">
              <svg className="w-12 h-12 mx-auto mb-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
              <p>No results yet. Paste text on the left to begin.</p>
            </div>
          ) : (
            extractedData.map((data, idx) => (
              <div key={idx} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 relative group hover:border-blue-300 transition">
                <div className="flex items-start justify-between mb-2">
                  <div className="flex gap-2">
                    <span className="text-[10px] uppercase font-bold text-blue-500 bg-blue-50 px-2 py-0.5 rounded">
                      {data.category}
                    </span>
                    {data.reportId && (
                      <span className="text-[10px] uppercase font-bold text-slate-500 bg-slate-100 px-2 py-0.5 rounded border border-slate-200">
                        {data.reportId}
                      </span>
                    )}
                  </div>
                  <span className="text-sm font-bold text-slate-800">{data.country} · {data.year}</span>
                </div>
                <h4 className="font-bold text-slate-800 mb-1">{data.topic}</h4>
                <div className="flex items-baseline gap-2 mb-3">
                  <span className="text-2xl font-black text-blue-600">{data.value}</span>
                  <span className="text-sm text-slate-500 font-medium">{data.unit}</span>
                </div>
                <div className="text-xs text-slate-400 flex items-center gap-1">
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101" />
                  </svg>
                  <span className="truncate">{data.source}</span>
                </div>
                <button 
                  onClick={() => {
                    const filtered = extractedData.filter((_, i) => i !== idx);
                    setExtractedData(filtered);
                  }}
                  className="absolute top-4 right-4 text-slate-300 hover:text-red-500 transition opacity-0 group-hover:opacity-100 p-1"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default SmartExtraction;
